function resetUpload(){const video=$('#calibrationVideo');if(video.dataset.objectUrl)URL.revokeObjectURL(video.dataset.objectUrl);video.removeAttribute('src');video.load();currentFile=null;currentMatchMeta=null;videoInput.value='';calibrationPoints=[];$('#startAnalysis').disabled=true;$('#analysisProgress').style.width='0';$('#analysisPercent').textContent='0%';setWorkflow(1);}

function initials(name){return name.trim().split(/\s+/).slice(0,2).map(x=>x[0]?.toUpperCase()).join('')||'P';}
function loadProfile(){
  const profile=JSON.parse(localStorage.getItem('padeliqProfile')||'null'); if(!profile)return;
  $('#profileName').value=profile.name;$('#playingSide').value=profile.side;$('#playerLevel').value=profile.level;$('#profileAge').value=profile.age||'';$('#profileGender').value=profile.gender||'';$('#profileArea').value=profile.area||'';$('#profileHomeClub').value=profile.homeClub||'';$('#benchmarkConsent').checked=Boolean(profile.benchmarkConsent);applyProfile(profile.name,profile.level);
}
function applyProfile(name,level){const init=initials(name);$('#navName').textContent=name;$('#welcomeName').textContent=name.split(' ')[0];$('#navAvatar').textContent=init;$('#profileAvatar').textContent=init;$('.user-chip small').textContent=level+' player';}
$('#profileForm').addEventListener('submit',async e=>{e.preventDefault();const profile={name:$('#profileName').value.trim(),side:$('#playingSide').value,level:$('#playerLevel').value,age:$('#profileAge').value,gender:$('#profileGender').value,area:$('#profileArea').value.trim(),homeClub:$('#profileHomeClub').value.trim(),benchmarkConsent:$('#benchmarkConsent').checked};localStorage.setItem('padeliqProfile',JSON.stringify(profile));await supabaseClient.auth.updateUser({data:{full_name:profile.name,playing_side:profile.side,level:profile.level,age:profile.age,gender:profile.gender,area:profile.area,home_club:profile.homeClub}});await saveProfileToBackend(profile);applyProfile(profile.name,profile.level);renderBenchmarks();$('#profileSaved').textContent='Profile saved';setTimeout(()=>$('#profileSaved').textContent='',2500);});

