function applyLanguage(language){
  const lang=translations[language]?language:'en', dict=translations[lang], fallback=translations.en;
  document.documentElement.lang=lang;localStorage.setItem('padeliqLanguage',lang);
  $$('.language-select').forEach(select=>select.value=lang);
  $$('[data-i18n]').forEach(el=>{if(el.children.length)return;const value=dict[el.dataset.i18n]||fallback[el.dataset.i18n];if(value)el.textContent=value;});
  $$('[data-i18n-html]').forEach(el=>{const value=dict[el.dataset.i18nHtml]||fallback[el.dataset.i18nHtml];if(value)el.innerHTML=value;});
  renderMatches();
}
$$('.language-select').forEach(select=>select.addEventListener('change',()=>applyLanguage(select.value)));

const supabaseClient=window.supabase.createClient('https://lsotekuhbrdtfmlyindd.supabase.co','sb_publishable_p7OOWIbybkMLLfRB1w8t6A_UxIXyarb');
async function submitContactForm(event){
  event.preventDefault();const form=event.currentTarget,button=$('button[type="submit"]',form),status=$('.form-status',form),data=new FormData(form);button.disabled=true;status.classList.remove('error');status.textContent='Sending…';
  const payload={first_name:String(data.get('firstName')||'').trim(),last_name:String(data.get('lastName')||'').trim(),email:String(data.get('email')||'').trim().toLowerCase(),subject:String(data.get('subject')||'').trim(),question:String(data.get('question')||'').trim(),user_id:currentUser?.id||null,source:form.id==='appContactForm'?'signed_in_app':'homepage',preferred_language:localStorage.getItem('padeliqLanguage')||'en'};
  const {error}=await supabaseClient.from('contact_messages').insert(payload);button.disabled=false;
  if(error){console.warn('Contact submission failed',error.message);status.classList.add('error');status.textContent='We could not send that yet. Please try again.';return;}
  form.reset();if(form.id==='appContactForm'&&currentUser)prefillContactForm();status.textContent='Thank you—your message has been received.';
}
function prefillContactForm(){const form=$('#appContactForm');if(!form||!currentUser)return;const parts=(currentUser.user_metadata?.full_name||'').trim().split(/\s+/);form.elements.firstName.value=parts.shift()||'';form.elements.lastName.value=parts.join(' ');form.elements.email.value=currentUser.email||'';}
$$('#publicContactForm,#appContactForm').forEach(form=>form.addEventListener('submit',submitContactForm));
$('#newsletterForm').addEventListener('submit',async event=>{event.preventDefault();const form=event.currentTarget,button=$('button',form),status=$('.form-status',form),email=form.elements.email.value.trim().toLowerCase();button.disabled=true;status.classList.remove('error');status.textContent='Joining…';const {error}=await supabaseClient.from('newsletter_subscribers').insert({email,preferred_language:localStorage.getItem('padeliqLanguage')||'en',source:'homepage'});button.disabled=false;if(error&&error.code!=='23505'){console.warn('Newsletter signup failed',error.message);status.classList.add('error');status.textContent='We could not add you yet. Please try again.';return;}form.reset();status.textContent='You’re on the list—welcome to PadelIQ!';});
function profileToRow(profile){return {user_id:currentUser.id,full_name:profile.name||'',playing_side:profile.side||null,player_level:profile.level||null,age:profile.age?Number(profile.age):null,gender:profile.gender||null,area:profile.area||null,home_club:profile.homeClub||null,benchmark_consent:Boolean(profile.benchmarkConsent),preferred_language:localStorage.getItem('padeliqLanguage')||'en'};}
function matchToRow(match){return {user_id:currentUser.id,match_name:match.title,played_at:match.isoDate||null,place:match.place||null,court_number:match.court||null,racket:match.racket||null,match_score:match.matchScore||null,position_score:Number.isFinite(Number(match.score))?Number(match.score):null,duration_seconds:match.result?.summary?.duration_seconds||null,video_filename:match.videoFilename||null,video_mime_type:match.videoMimeType||null,video_size_bytes:match.videoSizeBytes||null,analysis_status:match.result?'complete':'metadata_only',analysis_result:match.result||null};}
function rowToMatch(row){const played=row.played_at?new Date(`${row.played_at}T12:00:00`):new Date(row.created_at),months=['JAN','FEB','MAR','APR','MAY','JUN','JUL','AUG','SEP','OCT','NOV','DEC'];return {id:row.id,remoteId:row.id,date:String(played.getDate()).padStart(2,'0'),month:months[played.getMonth()],isoDate:row.played_at,title:row.match_name,place:row.place||'',court:row.court_number||'',racket:row.racket||'',matchScore:row.match_score||'',score:row.position_score==null?null:Number(row.position_score),result:row.analysis_result||null,videoFilename:row.video_filename||'',videoMimeType:row.video_mime_type||'',videoSizeBytes:row.video_size_bytes||null,detail:row.analysis_result?'Positioning report':'Match metadata'};}
async function saveProfileToBackend(profile){if(!currentUser)return;const {error}=await supabaseClient.from('profiles').upsert(profileToRow(profile),{onConflict:'user_id'});if(error){backendReady=false;console.warn('Profile database unavailable',error.message);return;}backendReady=true;}
async function saveMatchToBackend(match){if(!currentUser||!backendReady)return;const row=matchToRow(match);let response;if(match.remoteId)response=await supabaseClient.from('matches').update(row).eq('id',match.remoteId).select().single();else response=await supabaseClient.from('matches').insert(row).select().single();if(response.error){console.warn('Match database save failed',response.error.message);return;}match.remoteId=response.data.id;const custom=JSON.parse(localStorage.getItem('padeliqMatches')||'[]'),index=custom.findIndex(item=>item.id===match.id);if(index>=0){custom[index].remoteId=response.data.id;localStorage.setItem('padeliqMatches',JSON.stringify(custom));}}
async function syncBackendData(user){
  currentUser=user;const [{data:remoteProfile,error:profileError},{data:remoteMatches,error:matchesError}]=await Promise.all([supabaseClient.from('profiles').select('*').eq('user_id',user.id).maybeSingle(),supabaseClient.from('matches').select('*').eq('user_id',user.id).order('played_at',{ascending:false})]);
  if(profileError||matchesError){backendReady=false;console.warn('PadelIQ database schema is not ready');return;}
  backendReady=true;
  if(remoteProfile){const profile={name:remoteProfile.full_name,side:remoteProfile.playing_side||'Left',level:remoteProfile.player_level||'Competitive',age:remoteProfile.age||'',gender:remoteProfile.gender||'',area:remoteProfile.area||'',homeClub:remoteProfile.home_club||'',benchmarkConsent:remoteProfile.benchmark_consent};localStorage.setItem('padeliqProfile',JSON.stringify(profile));loadProfile();}
  const localMatches=JSON.parse(localStorage.getItem('padeliqMatches')||'[]');
  if(remoteMatches?.length){localStorage.setItem('padeliqMatches',JSON.stringify(remoteMatches.map(rowToMatch)));renderMatches();}
  else if(localMatches.length){for(const match of localMatches)await saveMatchToBackend(match);renderMatches();}
  const localProfile=JSON.parse(localStorage.getItem('padeliqProfile')||'null');if(!remoteProfile&&localProfile)await saveProfileToBackend(localProfile);
}
function showLanding(){ $('#landing').classList.remove('hidden');$('#authView').classList.add('hidden');$('#appShell').classList.add('hidden');window.scrollTo(0,0); }
function showAuth(mode='signup'){$('#landing').classList.add('hidden');$('#appShell').classList.add('hidden');$('#authView').classList.remove('hidden');switchAuth(mode);window.scrollTo(0,0);}
function switchAuth(mode){['signup','signin','reset','recovery'].forEach(name=>$('#'+name+'Form').classList.toggle('hidden',name!==mode));}
function showApp(user){
  $('#landing').classList.add('hidden');$('#authView').classList.add('hidden');$('#appShell').classList.remove('hidden');
  if(user){currentUser=user;const name=user.user_metadata?.full_name||user.email.split('@')[0];$('#profileEmail').value=user.email;prefillContactForm();const profile=JSON.parse(localStorage.getItem('padeliqProfile')||'null');if(!profile){$('#profileName').value=name;applyProfile(name,user.user_metadata?.level||'Competitive');}syncBackendData(user);}
  routeTo('dashboard');setTimeout(drawHeatmap,30);
}
$$('[data-auth]').forEach(button=>button.addEventListener('click',()=>showAuth(button.dataset.auth)));
$$('[data-switch-auth]').forEach(button=>button.addEventListener('click',()=>switchAuth(button.dataset.switchAuth)));
$('#backHome').addEventListener('click',showLanding);
$('#logoutButton').addEventListener('click',async()=>{await supabaseClient.auth.signOut();showLanding();});
$('#deleteAllMatches').addEventListener('click',async()=>{if(!window.confirm('Delete every saved match report, score and analysis result? This removes the records from your account and cannot be undone.'))return;if(currentUser&&backendReady)await supabaseClient.from('matches').delete().eq('user_id',currentUser.id);localStorage.removeItem('padeliqMatches');localStorage.setItem('padeliqDeletedDemoMatches',JSON.stringify(defaultMatches.map(match=>match.id)));liveAnalysisResult=null;renderMatches();$('#distanceStat').textContent='—';$('#distanceContext').textContent='Available after real tracking';$('#coverageStat').textContent='—';$('#coverageContext').textContent='Measured frames successfully tracked';drawHeatmap();showToast('All match data deleted');});

$('#signupForm').addEventListener('submit',async e=>{
  e.preventDefault();const email=$('#signupEmail').value.trim().toLowerCase(),password=$('#signupPassword').value,name=$('#signupName').value.trim();
  const redirectTo=location.origin==='null'?undefined:location.origin;
  const {data,error}=await supabaseClient.auth.signUp({email,password,options:{data:{full_name:name,playing_side:'Left',level:'Competitive'},emailRedirectTo:redirectTo}});
  if(error){$('#signupError').textContent=error.message;return;}
  localStorage.setItem('padeliqProfile',JSON.stringify({name,side:'Left',level:'Competitive'}));loadProfile();
  if(data.session)showApp(data.user);else{$('#signupError').classList.add('auth-success');$('#signupError').textContent='Account created. Check your email to confirm your address, then sign in.';}
});
$('#signinForm').addEventListener('submit',async e=>{
  e.preventDefault();const email=$('#signinEmail').value.trim().toLowerCase(),password=$('#signinPassword').value;
  const {data,error}=await supabaseClient.auth.signInWithPassword({email,password});
  if(error){$('#signinError').textContent=error.message;return;}loadProfile();showApp(data.user);
});
$('#resetForm').addEventListener('submit',async e=>{
  e.preventDefault();const email=$('#resetEmail').value.trim().toLowerCase(),redirectTo=location.origin==='null'?undefined:location.origin;
  const {error}=await supabaseClient.auth.resetPasswordForEmail(email,redirectTo?{redirectTo}:undefined);
  if(error){$('#resetError').textContent=error.message;return;}$('#resetError').classList.add('auth-success');$('#resetError').textContent='Reset link sent. Check your email.';
});
$('#recoveryForm').addEventListener('submit',async e=>{e.preventDefault();const {error}=await supabaseClient.auth.updateUser({password:$('#recoveryPassword').value});if(error){$('#recoveryError').textContent=error.message;return;}$('#recoveryError').classList.add('auth-success');$('#recoveryError').textContent='Password updated successfully.';setTimeout(async()=>{const {data}=await supabaseClient.auth.getUser();showApp(data.user);},900);});

renderMatches();loadProfile();applyLanguage(localStorage.getItem('padeliqLanguage')||'en');
$('#matchDate').valueAsDate=new Date();
supabaseClient.auth.onAuthStateChange((event,session)=>{if(event==='PASSWORD_RECOVERY'){showAuth('recovery');}else if(event==='SIGNED_IN'&&session?.user){showApp(session.user);}});
supabaseClient.auth.getSession().then(({data})=>{if(data.session?.user)showApp(data.session.user);else showLanding();});
